#include <stdio.h>
#include <math.h>

int gcd(int a, int b) {
    if (b == 0)
        return a;
    return gcd(b, a % b);
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        int arr[N];
        for (int i = 0; i < N; i++)
            scanf("%d", &arr[i]);
        int minDel = N;
        for (int mask = 0; mask < (1 << N); mask++) {
            int subset[N];
            int size = 0;
            for (int i = 0; i < N; i++)
                if ((mask & (1 << i)))
                    subset[size++] = arr[i];
            if (size == 0)
                continue;
            int g = subset[0];
            for (int i = 1; i < size; i++)
                g = gcd(g, subset[i]);
            if (g == 1)
                minDel = (minDel < N - size) ? minDel : N - size;
        }
        if (minDel == N)
            printf("-1\n");
        else
            printf("%d\n", minDel);
    }
    return 0;
}

