code.Java:
import java.util.Scanner;
public class Main {
    public static int gcd(int a, int b) {
        if (b == 0)
            return a;
        return gcd(b, a % b);
    }
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int[] arr = new int[N];
            for (int i = 0; i < N; i++)
                arr[i] = sc.nextInt();
            int minDel = N;
            for (int mask = 0; mask < (1 << N); mask++) {
                int[] subset = new int[N];
                int size = 0;
                for (int i = 0; i < N; i++)
                    if ((mask & (1 << i)) != 0)
                        subset[size++] = arr[i];
                if (size == 0)
                    continue;
                int g = subset[0];
                for (int i = 1; i < size; i++)
                    g = gcd(g, subset[i]);
                if (g == 1)
                    minDel = Math.min(minDel, N - size);
            }
            if (minDel == N)
                System.out.println(-1);
            else
                System.out.println(minDel);
        }
    }
}

