import math

def gcd(a, b):
    if b == 0:
        return a
    return gcd(b, a % b)

def main():
    T = int(input())
    for _ in range(T):
        N = int(input())
        arr = list(map(int, input().split()))
        minDel = N
        for mask in range(1 << N):
            subset = [arr[i] for i in range(N) if (mask & (1 << i))]
            if len(subset) == 0:
                continue
            g = subset[0]
            for i in range(1, len(subset)):
                g = gcd(g, subset[i])
            if g == 1:
                minDel = min(minDel, N - len(subset))
        if minDel == N:
            print(-1)
        else:
            print(minDel)
if __name__ == '__main__':
    main()

