    while (T-- > 0) {
        let N = +lines[idx++];
        let arr = lines[idx++].trim().split(' ').map(x => +x);
        let minDel = N;
        for (let mask = 0; mask < (1 << N); mask++) {
            let subset = [];
            for (let i = 0; i < N; i++)
                if ((mask & (1 << i)))
                    subset.push(arr[i]);
            if (subset.length == 0)
                continue;
            let g = subset[0];
            for (let i = 1; i < subset.length; i++)
                g = gcd(g, subset[i]);
            if (g == 1)
                minDel = Math.min(minDel, N - subset.length);
        }
        if (minDel == N)
            console.log(-1);
        else
            console.log(minDel);
    }
}
